public function GetInitialStateAttributeFlags($sAttCode, &$aReasons = array())
{
    $iFlags = parent::GetInitialStateAttributeFlags($sAttCode, $aReasons);
    if (!$this->IsNew()) {
        $iFlags |= OPT_ATT_READONLY;
    }
    return $iFlags;
}

protected function BeforeInsert()
{
    $iAgentId = $this->Get('agent');
    if (empty($iAgentId)) {
        throw new Exception('Выберите агента для запуска аудита');
    }
    $oAgent = MetaModel::GetObject('AuditAgent', $iAgentId, false);
    if (!$oAgent) {
        throw new Exception('Агент не найден');
    }
    $oUser = UserRights::GetUserObject();
    if (!$oUser) {
        throw new Exception('Пользователь не определён');
    }
    $iContactId = $oUser->Get('contactid');
    if (empty($iContactId)) {
        throw new Exception('У текущего пользователя не задан контакт');
    }
    $oPerson = MetaModel::GetObject('Person', $iContactId, false);
    if (!$oPerson) {
        throw new Exception('Контакт пользователя не найден');
    }
    $iOrgId = $oPerson->Get('org_id');
    if (empty($iOrgId)) {
        throw new Exception('У пользователя не указана организация');
    }
    $oOrg = MetaModel::GetObject('Organization', $iOrgId, false);
    if (!$oOrg) {
        throw new Exception('Организация не найдена');
    }
    $iTenantId = (int) $oOrg->Get('auditor_tenant_id');
    if ($iTenantId <= 0) {
        throw new Exception('Организация не синхронизирована с сервисом аудита');
    }
    $oSearch = new DBObjectSet(DBObjectSearch::FromOQL('SELECT UserExternal WHERE contactid = :cid'), array(), array('cid' => $iContactId));
    $oExtUser = $oSearch->Fetch();
    if (!$oExtUser) {
        throw new Exception('Внешний пользователь для этого контакта не найден. Выполните синхронизацию пользователя.');
    }
    $iAuditorUserId = (int) $oExtUser->Get('auditor_user_id');
    if ($iAuditorUserId <= 0) {
        throw new Exception('У пользователя не задан auditor_user_id. Выполните синхронизацию пользователя.');
    }
    if ((int) $oAgent->Get('organization') !== (int) $iOrgId) {
        throw new Exception('Агент не принадлежит организации текущего пользователя');
    }
    $sPublicId = $oAgent->Get('public_id');
    if (empty($sPublicId)) {
        throw new Exception('У агента не задан public_id');
    }
    $sToken = AuditAgentToken::Auditor_StaticGetServiceAccessToken();
    $aBody = array(
        'tenantId' => $iTenantId,
        'initiatedById' => $iAuditorUserId,
        'agentPublicId' => $sPublicId,
    );
    $sUrl = 'http://auditor-service:8081/internal/audits';
    $ch = curl_init($sUrl);
    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
    curl_setopt($ch, CURLOPT_POST, true);
    curl_setopt($ch, CURLOPT_HTTPHEADER, array(
        'Authorization: Bearer '.$sToken,
        'Content-Type: application/json',
        'Accept: application/json',
    ));
    curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($aBody));
    $sResult = curl_exec($ch);
    $iStatus = curl_getinfo($ch, CURLINFO_HTTP_CODE);
    curl_close($ch);
    if ($sResult === false) {
        throw new Exception('Ошибка вызова сервиса аудита: '.curl_error($ch));
    }
    if ($iStatus !== 201 && $iStatus !== 200) {
        throw new Exception('Сервис аудита вернул ошибку HTTP '.$iStatus.': '.$sResult);
    }
    $mResp = json_decode($sResult, true);
    $iAuditId = is_array($mResp) ? (int) (isset($mResp['id']) ? $mResp['id'] : reset($mResp)) : (int) $sResult;
    if ($iAuditId <= 0) {
        throw new Exception('Сервис аудита не вернул идентификатор аудита');
    }
    $this->Set('organization', $iOrgId);
    $this->Set('user', $oExtUser->GetKey());
    $this->Set('audit_id', $iAuditId);
    $this->Set('status', 'PENDING');
    $this->Set('created_at', date('Y-m-d H:i:s'));
    parent::BeforeInsert();
}

public function GetInitialStateAttributeFlags($sAttCode, &$aReasons = array())
{
    return parent::GetInitialStateAttributeFlags($sAttCode, $aReasons) | OPT_ATT_READONLY;
}

public function GetInitialStateAttributeFlags($sAttCode, &$aReasons = array())
{
    $iFlags = parent::GetInitialStateAttributeFlags($sAttCode, $aReasons);
    if ($this->IsNew())
    {
        if (!in_array($sAttCode, array('friendly_name','ttl_minutes')))
        {
            $iFlags |= OPT_ATT_HIDDEN;
        }
    }
    else
    {
        if ($sAttCode == 'ttl_minutes')
        {
            $iFlags |= OPT_ATT_READONLY;
        }
    }

    return $iFlags;
}

protected function AfterInsert()
{
    parent::AfterInsert();
    $ttl = (int)$this->Get('ttl_minutes');
    $response = $this->CallBackendToCreateToken($ttl);
    if (is_string($response)) {
        $response = json_decode($response, true);
    }

    $expiresAt = date('Y-m-d H:i:s', time() + ((int)$response['expiresInMinutes'] * 60));
    $this->Set('expires_at', $expiresAt);
    $this->AllowWrite();
    $this->DBUpdate();

    $_SESSION['audit_console_token_once'] = [
        'object_id' => $this->GetKey(),
        'token' => $response['registrationToken']
    ];
}

public function DisplayBareRelations(WebPage $oPage, $bEditMode = false)
{
    parent::DisplayBareRelations($oPage, $bEditMode);
    if (isset($_SESSION['audit_console_token_once']) && is_array($_SESSION['audit_console_token_once'])) {
        $data = $_SESSION['audit_console_token_once'];
        if (isset($data['object_id'], $data['token']) && $data['object_id'] == $this->GetKey()) {
            $token = $data['token'];
            unset($_SESSION['audit_console_token_once']);

            $html = '
            <div style="
                margin:20px 0;
                padding:20px;
                border-radius:8px;
                background:#e8f5e9;
                border:1px solid #2e7d32;
            ">
                <h3 style="margin-top:0;color:#2e7d32;">
                    Создан регистрационный токен
                </h3>
                <p style="margin:10px 0;">
                    Пожалуйста, скопируйте токен.
                </p>
                <div style="
                    font-size:18px;
                    font-weight:bold;
                    background:#ffffff;
                    padding:10px;
                    border-radius:5px;
                    border:1px dashed #2e7d32;
                    word-break:break-all;
                ">
                    '.$token.'
                </div>
            </div>';

            $oPage->add($html);
        }
    }
}

private function Auditor_GetServiceAccessToken()
{
    return self::Auditor_StaticGetServiceAccessToken();
}

public static function Auditor_StaticGetServiceAccessToken()
{
    $sTokenUrl = 'http://keycloak.local/realms/internal/protocol/openid-connect/token';
    $sClientId = 'itop';
    $sClientSecret = getenv('AUDITOR_ITOP_CLIENT_SECRET');
    if (empty($sClientSecret)) {
        throw new Exception('AUDITOR_ITOP_CLIENT_SECRET env var is not set');
    }

    $aPost = array(
        'grant_type' => 'client_credentials',
        'client_id' => $sClientId,
        'client_secret' => $sClientSecret,
    );

    $ch = curl_init($sTokenUrl);
    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
    curl_setopt($ch, CURLOPT_POST, true);
    curl_setopt($ch, CURLOPT_POSTFIELDS, http_build_query($aPost));
    curl_setopt($ch, CURLOPT_HTTPHEADER, array(
        'Content-Type: application/x-www-form-urlencoded',
    ));

    $sResult = curl_exec($ch);
    if ($sResult === false) {
        throw new Exception('Keycloak token request failed: '.curl_error($ch));
    }

    $iStatus = curl_getinfo($ch, CURLINFO_HTTP_CODE);
    curl_close($ch);

    if ($iStatus < 200 || $iStatus >= 300) {
        throw new Exception('Keycloak token HTTP '.$iStatus.': '.$sResult);
    }

    $aData = json_decode($sResult, true);
    if (!is_array($aData) || empty($aData['access_token'])) {
        throw new Exception('Keycloak token response invalid: '.$sResult);
    }

    return $aData['access_token'];
}

private function CallBackendToCreateToken($ttl)
{
    $ttl = (int)$ttl;
    $oCurUser = UserRights::GetUserObject();
    $sUserId = '';
    $iTenantId = 0;

    if ($oCurUser) {
        $sUserId = $oCurUser->Get('login');
        $iContactId = $oCurUser->Get('contactid');
        if (!empty($iContactId)) {
            $oPerson = MetaModel::GetObject('Person', $iContactId, false);
            if ($oPerson) {
                $iOrgId = $oPerson->Get('org_id');
                if (!empty($iOrgId)) {
                    $oOrg = MetaModel::GetObject('Organization', $iOrgId, false);
                    if ($oOrg) {
                        $iTenantId = (int) $oOrg->Get('auditor_tenant_id');
                    }
                }
            }
        }
    }

    if ($iTenantId <= 0) {
        throw new Exception('Tenant is not synchronized with auditor-service for current organization');
    }

    $aRoles = array();
    if (UserRights::IsAdministrator()) {
        $aRoles[] = 'ADMIN';
    } else {
        $aRoles[] = 'AUDITOR';
    }

    $aBody = array(
        'ttlMinutes' => $ttl,
        'userId' => $sUserId,
        'tenantId' => $iTenantId,
        'roles' => $aRoles,
    );

    $sUrl = 'http://auditor-service:8081/internal/token/registration-token';

    $ch = curl_init($sUrl);
    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
    curl_setopt($ch, CURLOPT_POST, true);
    curl_setopt($ch, CURLOPT_HTTPHEADER, array(
        'Authorization: Bearer '.$this->Auditor_GetServiceAccessToken(),
        'Content-Type: application/json',
        'Accept: application/json',
    ));
    curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($aBody));

    $sResult = curl_exec($ch);
    if ($sResult === false) {
        throw new Exception('Failed to call registration-token backend: '.curl_error($ch));
    }

    $iStatus = curl_getinfo($ch, CURLINFO_HTTP_CODE);
    curl_close($ch);

    if ($iStatus < 200 || $iStatus >= 300) {
        throw new Exception('Backend registration-token returned HTTP '.$iStatus.': '.$sResult);
    }

    $aData = json_decode($sResult, true);
    if (!is_array($aData) || !isset($aData['registrationToken'], $aData['expiresInMinutes'])) {
        throw new Exception('Unexpected backend response for registration-token: '.$sResult);
    }

    return $aData;
}

protected function AfterInsert()
{
    parent::AfterInsert();
    try {
        $sToken = $this->Auditor_GetServiceAccessToken();
        $this->Auditor_SyncOrganizations($sToken);
    } catch (Exception $e) {
        IssueLog::Error('AuditOrgSyncJob failed: '.$e->getMessage());
    }
}

private function Auditor_GetServiceAccessToken()
{
    return AuditAgentToken::Auditor_StaticGetServiceAccessToken();
}

private function Auditor_SyncOrganizations($sToken)
{
    $oSearch = DBObjectSearch::FromOQL("SELECT Organization");
    $oSet = new DBObjectSet($oSearch);

    while ($oOrg = $oSet->Fetch()) {
        $aBody = array(
            'name' => $oOrg->GetName(),
        );

        $sUrl = 'http://auditor-service:8081/api/tenants';

        $ch = curl_init($sUrl);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_POST, true);
        curl_setopt($ch, CURLOPT_HTTPHEADER, array(
            'Authorization: Bearer '.$sToken,
            'Content-Type: application/json',
            'Accept: application/json',
        ));
        curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($aBody));

        $sResult = curl_exec($ch);
        if ($sResult === false) {
            throw new Exception('auditor-service createTenant failed: '.curl_error($ch));
        }
        $iStatus = curl_getinfo($ch, CURLINFO_HTTP_CODE);
        curl_close($ch);

        if ($iStatus !== 201 && $iStatus !== 200) {
            IssueLog::Error('auditor-service createTenant HTTP '.$iStatus.': '.$sResult);
            continue;
        }

        $mData = json_decode($sResult, true);
        if (is_array($mData)) {
            $iTenantId = (int) reset($mData);
        } else {
            $iTenantId = (int) $sResult;
        }

        if ($iTenantId > 0 && (int)$oOrg->Get('auditor_tenant_id') === 0) {
            $oOrg->Set('auditor_tenant_id', $iTenantId);
            $oOrg->AllowWrite();
            $oOrg->DBUpdate();
        }
    }
}

