private function Auditor_SyncUserAudits($sToken)
{
    $iUserId = $this->Get('user');
    $oUser = MetaModel::GetObject('UserExternal', $iUserId, false);
    if (!$oUser) {
        throw new Exception('UserExternal not found for id '.$iUserId);
    }

    $sTenantName = 'Default';
    $iTenantId = 0;
    $iOrgId = 0;
    $iContactId = $oUser->Get('contactid');
    if (!empty($iContactId)) {
        $oPerson = MetaModel::GetObject('Person', $iContactId, false);
        if ($oPerson) {
            $iOrgId = $oPerson->Get('org_id');
            if (!empty($iOrgId)) {
                $oOrg = MetaModel::GetObject('Organization', $iOrgId, false);
                if ($oOrg) {
                    $sTenantName = $oOrg->GetName();
                    $iTenantId = (int) $oOrg->Get('auditor_tenant_id');
                }
            }
        }
    }

    if ($iTenantId <= 0) {
        throw new Exception('Tenant is not synchronized with auditor-service for organization '.$sTenantName);
    }

    $iAuditorUserId = (int) $oUser->Get('auditor_user_id');
    if ($iAuditorUserId <= 0) {
        throw new Exception('UserExternal '.$iUserId.' has no auditor_user_id');
    }

    $sUrl = 'http://auditor-service:8081/internal/audits/tenant/'.$iTenantId.'/user/'.$iAuditorUserId;

    $ch = curl_init($sUrl);
    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
    curl_setopt($ch, CURLOPT_HTTPHEADER, array(
        'Authorization: Bearer '.$sToken,
        'Accept: application/json',
    ));

    $sResult = curl_exec($ch);
    if ($sResult === false) {
        throw new Exception('auditor-service getAudits failed: '.curl_error($ch));
    }

    $iStatus = curl_getinfo($ch, CURLINFO_HTTP_CODE);
    curl_close($ch);

    if ($iStatus !== 200) {
        throw new Exception('auditor-service getAudits HTTP '.$iStatus.': '.$sResult);
    }

    $aData = json_decode($sResult, true);
    if (!is_array($aData)) {
        throw new Exception('Unexpected backend response for audits: '.$sResult);
    }

    $oExisting = new DBObjectSet(
        DBObjectSearch::FromOQL("SELECT CustomAudit WHERE user = :user"),
        array(),
        array('user' => $iUserId)
    );

    while ($oAudit = $oExisting->Fetch()) {
        $oAudit->DBDelete();
    }

    foreach ($aData as $aAudit) {
        if (!isset($aAudit['id'], $aAudit['status'])) {
            continue;
        }

        $iAuditId = (int) $aAudit['id'];
        $sStatus  = strtoupper($aAudit['status']);

        $sCreatedAt  = isset($aAudit['createdAt']) ? $aAudit['createdAt'] : null;
        $sStartedAt  = isset($aAudit['startedAt']) ? $aAudit['startedAt'] : null;
        $sCompletedAt = isset($aAudit['completedAt']) ? $aAudit['completedAt'] : null;

        $sCreatedAtDb = null;
        $sStartedAtDb = null;
        $sCompletedAtDb = null;

        if (!empty($sCreatedAt)) {
            $t = strtotime($sCreatedAt);
            if ($t !== false) {
                $sCreatedAtDb = date('Y-m-d H:i:s', $t);
            }
        }
        if (!empty($sStartedAt)) {
            $t = strtotime($sStartedAt);
            if ($t !== false) {
                $sStartedAtDb = date('Y-m-d H:i:s', $t);
            }
        }
        if (!empty($sCompletedAt)) {
            $t = strtotime($sCompletedAt);
            if ($t !== false) {
                $sCompletedAtDb = date('Y-m-d H:i:s', $t);
            }
        }

        $iCount = isset($aAudit['countInstalledSoftware']) ? (int) $aAudit['countInstalledSoftware'] : 0;

        $oNew = MetaModel::NewObject('CustomAudit');
        $oNew->Set('organization', $iOrgId);
        $oNew->Set('user', $iUserId);
        $oNew->Set('audit_id', $iAuditId);
        $oNew->Set('status', $sStatus);

        if ($sCreatedAtDb !== null) {
            $oNew->Set('created_at', $sCreatedAtDb);
        }
        if ($sStartedAtDb !== null) {
            $oNew->Set('started_at', $sStartedAtDb);
        }
        if ($sCompletedAtDb !== null) {
            $oNew->Set('completed_at', $sCompletedAtDb);
        }

        $oNew->Set('installed_software_count', $iCount);

        if (isset($aAudit['initiatedById'])) {
            $oNew->Set('auditor_user_id', (int) $aAudit['initiatedById']);
        }
        if (isset($aAudit['agentId'])) {
            $oNew->Set('auditor_agent_id', (int) $aAudit['agentId']);
        }

        $oNew->DBInsertNoReload();
    }
}

