        $this->Auditor_SyncAgents($sToken);
    } catch (Exception $e) {
        IssueLog::Error('AuditAgentSyncJob failed: '.$e->getMessage());
    }
}

private function Auditor_SyncAgents($sToken)
{
    $iOrgId = $this->Get('organization');
    $oOrg = MetaModel::GetObject('Organization', $iOrgId, false);
    if (!$oOrg) {
        throw new Exception('Organization not found for id '.$iOrgId);
    }

    $iTenantId = (int) $oOrg->Get('auditor_tenant_id');
    if ($iTenantId <= 0) {
        throw new Exception('Tenant is not synchronized with auditor-service for organization '.$oOrg->GetName());
    }

    $sUrl = 'http://auditor-service:8081/internal/agent/tenant/'.$iTenantId;

    $ch = curl_init($sUrl);
    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
    curl_setopt($ch, CURLOPT_HTTPHEADER, array(
        'Authorization: Bearer '.$sToken,
        'Accept: application/json',
    ));

    $sResult = curl_exec($ch);
    if ($sResult === false) {
        throw new Exception('auditor-service getAgents failed: '.curl_error($ch));
    }

    $iStatus = curl_getinfo($ch, CURLINFO_HTTP_CODE);
    curl_close($ch);

    if ($iStatus !== 200) {
        throw new Exception('auditor-service getAgents HTTP '.$iStatus.': '.$sResult);
    }

    $aData = json_decode($sResult, true);
    if (!is_array($aData)) {
        throw new Exception('Unexpected backend response for agents: '.$sResult);
    }

    $oExisting = new DBObjectSet(
        DBObjectSearch::FromOQL("SELECT AuditAgent WHERE organization = :organization"),
        array(),
        array('organization' => $iOrgId)
    );

    while ($oAgent = $oExisting->Fetch()) {
        $oAgent->DBDelete();
    }

    foreach ($aData as $aAgent) {
        if (!isset($aAgent['publicId'], $aAgent['osType'])) {
            continue;
        }

        $sPublicId = $aAgent['publicId'];
        $sOsType = strtoupper($aAgent['osType']);

        $oNew = MetaModel::NewObject('AuditAgent');
        $oNew->Set('organization', $iOrgId);
        $oNew->Set('public_id', $sPublicId);
        $oNew->Set('os_type', $sOsType);

        $oNew->DBInsertNoReload();
    }
}
